mapper.update:
UPDATE member
SET member_status = 1
WHERE member_idx = #{member_idx}

mapper.select:
SELECT * FROM(
SELECT @RN:=@RN+1 AS rnum, a.* FROM(
SELECT * FROM member
WHERE member_status = 0 
ORDER BY member_idx DESC
) a, (SELECT @RN:=0) b
) c WHERE c.rnum BETWEEN #{begin} AND #{end}

